### 5. 创建 Agent (internal/agent/)

#### 方式一：使用 Flow (ReAct Agent)

```go
package agent

import (
    "context"

    "github.com/cloudwego/eino/flow/agent/react"
    "github.com/cloudwego/eino/compose"
    "github.com/cloudwego/eino/components/tool"
    "github.com/cloudwego/eino/components/model"
)

// ReactAgent ReAct 风格的 Agent
type ReactAgent struct {
    agent *react.Agent
}

// NewReactAgent 创建 ReAct Agent
func NewReactAgent(ctx context.Context, chatModel model.ChatModel, tools []tool.BaseTool) (*ReactAgent, error) {
    agent, err := react.NewAgent(ctx, &react.AgentConfig{
        ToolCallingModel: chatModel,
        ToolsConfig: compose.ToolsNodeConfig{
            Tools: tools,
        },
        // 可选：设置最大迭代次数
        MaxStep: 10,
    })
    if err != nil {
        return nil, err
    }

    return &ReactAgent{agent: agent}, nil
}

// Run 运行 Agent
func (a *ReactAgent) Run(ctx context.Context, userInput string) (string, error) {
    messages := []*schema.Message{
        {Role: schema.User, Content: userInput},
    }

    // 流式执行
    stream, err := a.agent.Stream(ctx, messages)
    if err != nil {
        return "", err
    }

    var result strings.Builder
    for {
        msg, err := stream.Recv()
        if err == io.EOF {
            break
        }
        if err != nil {
            return "", err
        }
        result.WriteString(msg.Content)
    }

    return result.String(), nil
}
```

#### 方式二：使用 ADK (推荐)

```go
package agent

import (
    "context"

    "github.com/cloudwego/eino/adk"
    "github.com/cloudwego/eino/compose"
    "github.com/cloudwego/eino/components/tool"
    "github.com/cloudwego/eino/components/model"
