// ChatAgent ADK 风格的 Agent
type ChatAgent struct {
    agent adk.Agent
}

// NewChatAgent 创建 ADK ChatModel Agent
func NewChatAgent(ctx context.Context, chatModel model.ChatModel, tools []tool.BaseTool) (*ChatAgent, error) {
    agent, err := adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
        Name:        "assistant",
        Description: "A helpful AI assistant",
        Instruction: "You are a helpful AI assistant. Use tools when necessary.",
        Model:       chatModel,
        ToolsConfig: adk.ToolsConfig{
            ToolsNodeConfig: compose.ToolsNodeConfig{
                Tools: tools,
            },
        },
    })
    if err != nil {
        return nil, err
    }

    return &ChatAgent{agent: agent}, nil
}

// Run 运行 Agent
func (a *ChatAgent) Run(ctx context.Context, userInput string) (string, error) {
    result, err := a.agent.Run(ctx, &adk.RunConfig{
        Input: userInput,
    })
    if err != nil {
        return "", err
    }
    return result.Output, nil
}
