### 6. 多 Agent 编排

```go
package agent

import (
    "context"

    "github.com/cloudwego/eino/adk"
    "github.com/cloudwego/eino/skills/adk/supervisor"
    "github.com/cloudwego/eino/components/model"
)

// MultiAgent 多 Agent 系统
type MultiAgent struct {
    supervisor adk.Agent
}

// NewMultiAgent 创建多 Agent 系统
func NewMultiAgent(ctx context.Context, chatModel model.ChatModel) (*MultiAgent, error) {
    // 1. 创建子 Agent
    searchAgent, err := adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
        Name:        "search_agent",
        Description: "Search for information on the internet",
        Instruction: "You are a search specialist. Find relevant information.",
        Model:       chatModel,
    })
    if err != nil {
        return nil, err
    }

    mathAgent, err := adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
        Name:        "math_agent",
        Description: "Perform mathematical calculations",
        Instruction: "You are a math specialist. Solve math problems.",
        Model:       chatModel,
    })
    if err != nil {
        return nil, err
    }

    // 2. 创建 Supervisor
    superAgent, err := adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
        Name:        "supervisor",
        Description: "Route tasks to appropriate agents",
        Instruction: `You are a supervisor. You manage two agents:
- search_agent: for searching information
- math_agent: for math calculations
Route tasks to the appropriate agent based on the user's request.`,
        Model: chatModel,
        Exit:   &adk.ExitTool{},  // 添加退出工具
    })
    if err != nil {
        return nil, err
    }

    // 3. 组装多 Agent
    multiAgent, err := supervisor.New(ctx, &supervisor.Config{
        Supervisor: superAgent,
        SubAgents:  []adk.Agent{searchAgent, mathAgent},
    })
    if err != nil {
        return nil, err
    }

    return &MultiAgent{supervisor: multiAgent}, nil
}

// Run 运行多 Agent
func (a *MultiAgent) Run(ctx context.Context, userInput string) (string, error) {
    result, err := a.supervisor.Run(ctx, &adk.RunConfig{
        Input: userInput,
    })
    if err != nil {
        return "", err
    }
    return result.Output, nil
}
```

