### 2. 使用 Callbacks 实现流式输出（推荐）

```go
package agent

import (
    "context"
    "fmt"

    "github.com/cloudwego/eino/callbacks"
    "github.com/cloudwego/eino/schema"
)

// StreamHandler 流式输出处理器
type StreamHandler struct {
    callbacks.Handler
    OnToken func(token string)  // 每个 token 的回调
}

// OnChatModelStream LLM 流式输出时触发
func (h *StreamHandler) OnChatModelStream(ctx context.Context, info *callbacks.RunInfo, input *callbacks.ModelStreamInput) context.Context {
    for _, msg := range input.Message {
        h.OnToken(msg.Content)
    }
    return ctx
}

// RunWithStream 带流式输出的运行
func (a *ReactAgent) RunWithStream(ctx context.Context, userInput string, onToken func(token string)) (string, error) {
    // 注册回调
    handler := &StreamHandler{
        OnToken: onToken,
    }
    ctx = callbacks.SetHandler(ctx, handler)

    messages := []*schema.Message{
        {Role: schema.User, Content: userInput},
    }

    // 流式执行
    stream, err := a.agent.Stream(ctx, messages)
    if err != nil {
        return "", err
    }

    var result strings.Builder
    for {
        msg, err := stream.Recv()
        if err == io.EOF {
            break
        }
        if err != nil {
            return "", err
        }
        result.WriteString(msg.Content)
    }

    return result.String(), nil
}
