## 🔧 更优雅的流式处理

```go
package agent

import (
    "context"
    "io"
    "github.com/cloudwego/eino/schema"
)

// StreamResult 流式结果
type StreamResult struct {
    Channel <-chan string// 输出通道
    Error   chan error// 错误通道
}

// StreamAsync 异步流式输出
func (a *ReactAgent) StreamAsync(ctx context.Context, userInput string) *StreamResult {
    outputChan := make(chan string)
    errorChan := make(chan error, 1)

    go func() {
        defer close(outputChan)
        defer close(errorChan)

        messages := []*schema.Message{
            {Role: schema.User, Content: userInput},
        }

        stream, err := a.agent.Stream(ctx, messages)
        if err != nil {
            errorChan <- err
            return
        }

        for {
            msg, err := stream.Recv()
            if err == io.EOF {
                return
            }
            if err != nil {
                errorChan <- err
                return
            }

            select {
            case outputChan <- msg.Content:
            case <-ctx.Done():
                return
            }
        }
    }()

    return &StreamResult{
        Channel: outputChan,
        Error:   errorChan,
    }
}

// 使用示例
func main() {
    // ... 创建 agentresult := agent.StreamAsync(ctx, "今天北京天气怎么样？")

    for {
        select {
        case token, ok := <-result.Channel:
            if !ok {
                return
            }
            fmt.Print(token)  // 实时输出
        case err := <-result.Error:
            fmt.Printf("Error: %v\n", err)
            return
        case <-ctx.Done():
            return
        }
    }
}
```

