### 三、Lambda 的四种函数类型

Lambda 是最灵活的组件，支持四种函数签名：

```go
// 1. InvokableLambda - 只处理 Invoke
compose.InvokableLambda(func(ctx context.Context, input string) (string, error) {
    return "processed: " + input, nil
})

// 2. StreamableLambda - 只处理 Stream
compose.StreamableLambda(func(ctx context.Context, input string) (*schema.StreamReader[string], error) {
    sr, sw := schema.Pipe[string](0)
    go func() {
        defer sw.Close()
        for _, char := range input {
            sw.Send(string(char), nil)  // 逐字符发送
        }
    }()
    return sr, nil
})

// 3. CollectableLambda - 只处理 Collect
compose.CollectableLambda(func(ctx context.Context, input *schema.StreamReader[string]) (string, error) {
    var result string
    for {
        chunk, err := input.Recv()
        if err == io.EOF {
            break
        }
        result += chunk
    }
    return result, nil
})

// 4. TransformableLambda - 处理 Transform（流→流）
compose.TransformableLambda(func(ctx context.Context, input *schema.StreamReader[string]) (*schema.StreamReader[string], error) {
    return schema.StreamReaderWithConvert(input, func(s string) (string, error) {
        return strings.ToUpper(s), nil
    }), nil
})

// 5. AnyLambda - 支持全部四种方式
compose.AnyLambda(
    invokeFunc,   // Invoke
    streamFunc,   // Stream
    collectFunc,  // Collect
    transformFunc, // Transform
)
```

