#### 2.优雅的流式处理函数

```go
package streamutil

import (
    "context"
    "io"
    "github.com/cloudwego/eino/schema"
)

// ProcessStream 处理流式输出的通用函数
func ProcessStream[T any](stream *schema.StreamReader[T], handler func(T)) error {
    defer stream.Close()

    for {
        item, err := stream.Recv()
        if err == io.EOF {
            return nil
        }
        if err != nil {
            return err
        }
        handler(item)
    }
}

// CollectStream 收集流式输出为完整结果
func CollectStream[T any](stream *schema.StreamReader[T]) ([]T, error) {
    defer stream.Close()

    var results []T
    for {
        item, err := stream.Recv()
        if err == io.EOF {
            return results, nil
        }
        if err != nil {
            return nil, err
        }
        results = append(results, item)
    }
}

// StreamToChannel 将流转换为 channel（更易用）
func StreamToChannel[T any](ctx context.Context, stream *schema.StreamReader[T]) <-chan T {
    ch := make(chan T)

    go func() {
        defer close(ch)
        defer stream.Close()

        for {
            select {
            case <-ctx.Done():
                return
            default:
                item, err := stream.Recv()
                if err == io.EOF {
                    return
                }
                if err != nil {
                    return
                }
                ch <- item
            }
        }
    }()

    return ch
}

// 使用示例
for chunk := range streamutil.StreamToChannel(ctx, stream) {
    fmt.Print(chunk.Content)
}
```

#### 3. SSE HTTP 服务（生产级）

```go
// HTTP SSE 流式响应
func handleChat(ctx context.Context, c *app.RequestContext, runner *adk.Runner) {
    query := c.Query("query")
    iter := runner.Query(ctx, query)

    s := sse.NewStream(c)
    defer c.Flush()

    for {
        event, ok := iter.Next()
        if !ok {
            break
        }

        // 处理流式消息
        if stream := event.Output.MessageOutput.MessageStream; stream != nil {
            for {
                chunk, err := stream.Recv()
                if errors.Is(err, io.EOF) {
                    break
                }

                // 发送 SSE 事件
                s.Publish(&sse.Event{
                    Data: json.Marshal(SSEEvent{
                        Type:    "stream_chunk",
                        Content: chunk.Content,
                    }),
                })
            }
        }
    }
}
```

#### 4. Callbacks 流式监听

```go
type StreamCallback struct {
    callbacks.HandlerBuilder
    OnToken func(token string)  // 每个 token 的回调
}

// OnEndWithStreamOutput 流式输出结束时触发
func (cb *StreamCallback) OnEndWithStreamOutput(ctx context.Context, 
    info *callbacks.RunInfo, 
    output *schema.StreamReader[callbacks.CallbackOutput],
) context.Context {

    go func() {
        defer output.Close()

        for {
            frame, err := output.Recv()
            if errors.Is(err, io.EOF) {
                break
            }
            if err != nil {
                return
            }

            // 处理每个流式帧
            if msg := frame.Message; msg != nil {
                cb.OnToken(msg.Content)
            }
        }
    }()

    return ctx
}

// 使用
ctx = callbacks.SetHandler(ctx, &StreamCallback{
    OnToken: func(token string) {
        fmt.Print(token)  // 实时打印
    },
})
```

