### 五、最佳实践

#### 1. 资源管理

```go
// ✅ 正确：defer Close
stream, err := model.Stream(ctx, messages)
if err != nil {
    return err
}
defer stream.Close()

// ❌ 错误：忘记 Close（可能导致资源泄漏）
stream, err := model.Stream(ctx, messages)
// 没有 defer stream.Close()
```

#### 2. 错误处理

```go
for {
    msg, err := stream.Recv()

    // ✅ 正确：区分 EOF 和其他错误
    if errors.Is(err, io.EOF) {
        break// 正常结束
    }
    if err != nil {
        return err  // 异常错误
    }

    // ❌ 错误：不区分 EOF
    if err != nil {
        break// 可能遗漏真正的错误
    }
}
```

#### 3. Tool Call 流式处理

```go
// ToolCall 可能跨多个 chunk，需要收集合并
toolCallsMap := make(map[int][]*schema.Message)

for {
    chunk, err := stream.Recv()
    if errors.Is(err, io.EOF) {
        break
    }

    // 收集 ToolCall chunks
    if len(chunk.ToolCalls) > 0 {
        for _, tc := range chunk.ToolCalls {
            if tc.Index != nil {
                toolCallsMap[*tc.Index] = append(toolCallsMap[*tc.Index], chunk)
            }
        }
    }
}

// 合并同一Index 的 ToolCall
for _, msgs := range toolCallsMap {
    fullMsg, _ := schema.ConcatMessages(msgs)
    // 现在可以执行完整的 ToolCall
    executeToolCall(fullMsg.ToolCalls[0])
}
```

