## 🔧 审批工具（需要审批）

```go
// 有判断逻辑，第一次中断，第二次执行
func approvalTool(ctx context.Context, args string) (string, error) {
    wasInterrupted, _, storedArgs := GetInterruptState[string](ctx)

    if !wasInterrupted {
        // 第一次：中断等待审批
        return "", StatefulInterrupt(ctx, &ApprovalInfo{
            Message: "是否允许执行此操作？",
            Args: args,
        }, args)
    }

    // 第二次：读取审批结果
    _, _, result := GetResumeContext[*ApprovalResult](ctx)
    if result.Approved {
        return doRealWork(storedArgs)
    }
    return "用户拒绝", nil
}
```

