## 🔧 动态审批（根据条件决定）

```go
// 有条件判断，敏感操作才中断
func smartTool(ctx context.Context, args *ActionArgs) (string, error) {
    wasInterrupted, _, storedArgs := GetInterruptState[*ActionArgs](ctx)

    // ========== 第二次调用（Resume后）==========
    if wasInterrupted {
        _, _, result := GetResumeContext[*ApprovalResult](ctx)
        if result.Approved {
            return doRealWork(storedArgs)
        }
        return "用户拒绝", nil
    }

    // ========== 第一次调用 ==========
    // 根据操作类型决定是否需要审批
    if args.Action == "delete" || args.Action == "send_email" {
        // 敏感操作：需要审批
        return "", StatefulInterrupt(ctx, &ApprovalInfo{
            Message: "这是一个敏感操作，需要审批",
            Args: args,
        }, args)
    }

    // 非敏感操作：直接执行，不中断
    return doRealWork(args), nil
}
```

